// SugarGuard.Web/wwwroot/js/interop.js
// Shared Blazor JS interop helpers.
// namespace: window.SugarGuard

(function () {
    'use strict';

    /**
     * Programmatically clicks a DOM element by id.
     * Used by Razor code for hidden file inputs and similar controls.
     * @param {string} id
     */
    function clickById(id) {
        const el = document.getElementById(id);
        if (el && typeof el.click === 'function') {
            el.click();
        }
    }

    /**
     * Downloads CSV content generated by Blazor.
     * @param {string} fileName
     * @param {string} content
     */
    function downloadCsv(fileName, content) {
        const blob = new Blob([content || ''], { type: 'text/csv;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');

        link.href = url;
        link.download = fileName || 'sugarguard-export.csv';
        link.style.display = 'none';
        document.body.appendChild(link);
        link.click();
        link.remove();
        URL.revokeObjectURL(url);
    }

window.SugarGuard = window.SugarGuard || {};

window.SugarGuard.articleEditor = window.SugarGuard.articleEditor || {
    wrapSelection: function (id, before, after) {
        const input = document.getElementById(id);
        if (!input) return;
        const start = input.selectionStart || 0;
        const end = input.selectionEnd || start;
        const selected = input.value.slice(start, end) || "текст";
        input.setRangeText(before + selected + after, start, end, "end");
        input.dispatchEvent(new Event("input", { bubbles: true }));
        input.focus();
    },
    insertAtCursor: function (id, text) {
        const input = document.getElementById(id);
        if (!input) return;
        const start = input.selectionStart || 0;
        const end = input.selectionEnd || start;
        input.setRangeText(text, start, end, "end");
        input.dispatchEvent(new Event("input", { bubbles: true }));
        input.focus();
    }
};
    window.SugarGuard.clickById = clickById;
    window.SugarGuard.downloadCsv = downloadCsv;
    window.SugarGuard.downloadBase64 = function (fileName, contentType, base64) {
        const binary = atob(base64 || '');
        // Файл уже подготовлен сервером: не добавляем и не заменяем BOM в браузере.
        // Это сохраняет корректную UTF-16 LE кодировку CSV для Microsoft Excel.
        const bytes = new Uint8Array(binary.length);
        for (let index = 0; index < binary.length; index += 1) {
            bytes[index] = binary.charCodeAt(index);
        }

        const blob = new Blob([bytes], { type: contentType || 'application/octet-stream' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = fileName || 'sugarguard-export';
        link.style.display = 'none';
        document.body.appendChild(link);
        link.click();
        // Загрузка запускается асинхронно. Немедленное освобождение URL иногда
        // отменяет её в Chromium/WebKit, поэтому очищаем ресурсы после старта.
        window.setTimeout(function () {
            link.remove();
            URL.revokeObjectURL(url);
        }, 1000);
    };
})();
